import { db, type DocumentRow, type LessonPlanRow } from '../db.ts'
import { generatePlan } from '../ai/plan.ts'
import { createAllQuizzes } from './quizzes.ts'
import { NotFoundError, BadRequestError } from '../errors.ts'

type Difficulty = 'beginner' | 'intermediate' | 'advanced'
type PlanStatus = 'draft' | 'approved' | 'completed'

export interface Objective {
  text: string
  topic: string
  question_count: number
}

export async function createPlan(documentId: number) {
  const doc = db.prepare(`SELECT * FROM documents WHERE id = ?`).get(documentId) as DocumentRow | undefined
  if (!doc) throw new NotFoundError('Document not found')
  if (doc.status !== 'ready' || !doc.markdown) {
    throw new BadRequestError(`Document is not ready for plan generation (status: ${doc.status})`)
  }

  const plan = await generatePlan(doc.markdown, doc.filename)
  const objectivesJson = JSON.stringify(plan.objectives)
  const res = db
    .prepare(
      `INSERT INTO lesson_plans (document_id, title, description, objectives, difficulty, status)
       VALUES (?, ?, ?, ?, ?, 'draft')
       RETURNING *`
    )
    .get(documentId, plan.title, plan.description, objectivesJson, plan.difficulty) as LessonPlanRow

  return rowToPlan(res)
}

export async function revisePlan(planId: number, feedback: string) {
  const row = db.prepare(`SELECT * FROM lesson_plans WHERE id = ?`).get(planId) as LessonPlanRow | undefined
  if (!row) throw new NotFoundError('Plan not found')
  if (row.status !== 'draft') {
    throw new BadRequestError('Only draft lesson plans can be revised')
  }

  const doc = db.prepare(`SELECT * FROM documents WHERE id = ?`).get(row.document_id) as DocumentRow | undefined
  if (!doc) throw new NotFoundError('Document not found')
  if (!doc.markdown) throw new BadRequestError('Document has no markdown content')

  const plan = await generatePlan(doc.markdown, doc.filename, feedback)
  const objectivesJson = JSON.stringify(plan.objectives)

  // Discard any quizzes generated for the previous draft.
  db.prepare(`DELETE FROM quiz_questions WHERE lesson_plan_id = ?`).run(planId)

  const updated = db
    .prepare(
      `UPDATE lesson_plans
       SET title = ?, description = ?, objectives = ?, difficulty = ?, revision_count = revision_count + 1, revision_feedback = ?
       WHERE id = ?
       RETURNING *`
    )
    .get(plan.title, plan.description, objectivesJson, plan.difficulty, feedback, planId) as LessonPlanRow

  return rowToPlan(updated)
}

export async function getPlan(planId: number) {
  const row = db.prepare(`SELECT * FROM lesson_plans WHERE id = ?`).get(planId) as LessonPlanRow | undefined
  if (!row) return null
  const doc = db.prepare(`SELECT filename FROM documents WHERE id = ?`).get(row.document_id)
  return {
    ...rowToPlan(row),
    document_filename: (doc as { filename: string } | undefined)?.filename
  }
}

export async function getPlansForDocument(documentId: number) {
  const rows = db
    .prepare(`SELECT * FROM lesson_plans WHERE document_id = ? ORDER BY datetime(created_at) DESC`)
    .all(documentId) as LessonPlanRow[]
  return rows.map(rowToPlan)
}

export async function approvePlan(planId: number) {
  const row = db.prepare(`SELECT * FROM lesson_plans WHERE id = ?`).get(planId) as LessonPlanRow | undefined
  if (!row) throw new NotFoundError('Plan not found')
  if (row.status === 'draft') {
    await createAllQuizzes(planId)
  }
  return getPlan(planId)
}

function rowToPlan(row: LessonPlanRow) {
  return {
    id: row.id,
    document_id: row.document_id,
    title: row.title,
    description: row.description,
    difficulty: row.difficulty as Difficulty,
    objectives: JSON.parse(row.objectives) as Objective[],
    status: row.status as PlanStatus,
    revision_count: row.revision_count,
    revision_feedback: row.revision_feedback,
    created_at: row.created_at
  }
}

import { db, type QuizQuestionRow } from '../db.ts'
import { generateAllQuizzes } from '../ai/quiz.ts'
import { generateRetryHint, explainCorrect, aiChat } from '../ai/feedback.ts'
import { getPlan } from './plans.ts'
import { getDocumentMarkdown } from './documents.ts'
import { NotFoundError, BadRequestError } from '../errors.ts'

export interface QuizDTO {
  id: number
  objectiveIndex: number
  questionIndex: number
  objectiveText: string
  question: string
  options: string[]
  hint: string
}

export async function createAllQuizzes(planId: number): Promise<QuizDTO[]> {
  const plan = await getPlan(planId)
  if (!plan) throw new NotFoundError('Plan not found')

  const markdown = await getDocumentMarkdown(plan.document_id)
  if (!markdown) throw new BadRequestError('Source document has no markdown content')

  const batch = await generateAllQuizzes(
    markdown,
    plan.objectives.map((o) => ({ text: o.text, topic: o.topic, question_count: o.question_count }))
  )

  const expectedSlots = new Set<string>()
  for (let i = 0; i < plan.objectives.length; i++) {
    for (let j = 0; j < plan.objectives[i].question_count; j++) {
      expectedSlots.add(`${i}-${j}`)
    }
  }
  const generatedSlots = new Set(batch.questions.map((q) => `${q.objective_index}-${q.question_index}`))
  if (expectedSlots.size !== generatedSlots.size || ![...expectedSlots].every((s) => generatedSlots.has(s))) {
    throw new BadRequestError(
      `Expected ${expectedSlots.size} questions matching the lesson plan, but the AI returned ${generatedSlots.size}. Please try approving again.`
    )
  }

  const insert = db.prepare(
    `INSERT INTO quiz_questions (lesson_plan_id, objective_index, question_index, objective_text, question, options, correct_index, explanation, hint)
     VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)`
  )
  const deleteExisting = db.prepare(`DELETE FROM quiz_questions WHERE lesson_plan_id = ?`)
  const updateStatus = db.prepare(`UPDATE lesson_plans SET status = 'approved' WHERE id = ?`)

  const save = db.transaction((questions: typeof batch.questions) => {
    deleteExisting.run(planId)
    for (const q of questions) {
      const objective = plan.objectives[q.objective_index]
      if (!objective) throw new BadRequestError(`Invalid objective_index ${q.objective_index} in generated batch`)
      if (q.question_index < 0 || q.question_index >= objective.question_count) {
        throw new BadRequestError(`Invalid question_index ${q.question_index} for objective ${q.objective_index}`)
      }
      insert.run(
        planId,
        q.objective_index,
        q.question_index,
        objective.text,
        q.question,
        JSON.stringify(q.options),
        q.correct_index,
        q.explanation,
        q.hint
      )
    }
    updateStatus.run(planId)
  })

  save(batch.questions)

  return getAllQuizzes(planId)
}

export async function getAllQuizzes(planId: number): Promise<QuizDTO[]> {
  const plan = await getPlan(planId)
  if (!plan) return []
  const rows = db
    .prepare(`SELECT * FROM quiz_questions WHERE lesson_plan_id = ? ORDER BY objective_index ASC, question_index ASC`)
    .all(planId) as QuizQuestionRow[]
  return rows.map(rowToDto)
}

export async function getQuizInternal(quizId: number): Promise<QuizQuestionRow | null> {
  return (db.prepare(`SELECT * FROM quiz_questions WHERE id = ?`).get(quizId) as QuizQuestionRow | undefined) ?? null
}

export async function getHint(quizId: number, previousGuessIndex: number | null): Promise<string> {
  const quiz = await getQuizInternal(quizId)
  if (!quiz) throw new NotFoundError('Quiz not found')
  const plan = await getPlan(quiz.lesson_plan_id)
  if (!plan) throw new NotFoundError('Plan not found')
  const markdown = await getDocumentMarkdown(plan.document_id)
  if (!markdown) throw new BadRequestError('Source document has no markdown content')
  const options = JSON.parse(quiz.options) as string[]
  return generateRetryHint(
    markdown,
    quiz.question,
    options,
    previousGuessIndex !== null ? options[previousGuessIndex] : null
  )
}

interface ExplanationResult {
  explanation: string
  correctIndex: number
}

export async function getExplanation(quizId: number): Promise<ExplanationResult> {
  const quiz = await getQuizInternal(quizId)
  if (!quiz) throw new NotFoundError('Quiz not found')
  const plan = await getPlan(quiz.lesson_plan_id)
  if (!plan) throw new NotFoundError('Plan not found')
  const markdown = await getDocumentMarkdown(plan.document_id)
  if (!markdown) throw new BadRequestError('Source document has no markdown content')
  const options = JSON.parse(quiz.options) as string[]
  const correct = options[quiz.correct_index]
  const explanation = await explainCorrect(markdown, quiz.question, options, correct, quiz.correct_index)
  return { explanation, correctIndex: quiz.correct_index }
}

export interface AnswerOutput {
  correct: boolean
}

export async function checkAnswer(quizId: number, learnerIndex: number): Promise<AnswerOutput> {
  const quiz = await getQuizInternal(quizId)
  if (!quiz) throw new NotFoundError('Quiz not found')
  const correct = learnerIndex === quiz.correct_index
  return { correct }
}

interface AI_Message {
  role: 'user' | 'assistant'
  content: string
}
export type MessageHistory = Array<AI_Message>

export async function getAiHelp(id: number, question: string, history: MessageHistory): Promise<string> {
  const quiz = await getQuizInternal(id)
  if (!quiz) throw new NotFoundError('Quiz not found')
  const plan = await getPlan(quiz.lesson_plan_id)
  if (!plan) throw new NotFoundError('Plan not found')
  const markdown = await getDocumentMarkdown(plan.document_id)
  if (!markdown) throw new BadRequestError('Source document has no markdown content')
  const options = JSON.parse(quiz.options) as string[]
  return aiChat(markdown, quiz.question, options, question, history)
}

function rowToDto(row: QuizQuestionRow): QuizDTO {
  return {
    id: row.id,
    objectiveIndex: row.objective_index,
    questionIndex: row.question_index,
    objectiveText: row.objective_text,
    question: row.question,
    options: JSON.parse(row.options),
    hint: row.hint
  }
}

